import { createSlice } from "@reduxjs/toolkit"

//המצב התחלתי של המשתמש
const initialState = {
    currentUser: { customerName: "guest" }
};

//;;

const userReducer = createSlice({
    name: "user",
    initialState,
    reducers: {
        //עדכון המשתמש הנוכחי
        set_currentUser: (state, action) => {
            state.currentUser = action.payload;
        }
    }
});
